use swc_ecma_ast::*;
use regex::Regex;
use lazy_static::lazy_static;

lazy_static! {
    static ref RE_NON_ALPHANUMERIC: Regex = Regex::new(r"[^A-Za-z0-9_]").unwrap();
    static ref RE_UNDERSCORES: Regex = Regex::new(r"_+").unwrap();
    static ref RE_START_ALPHABETIC: Regex = Regex::new(r"^[A-Za-z_]").unwrap();
}

pub fn sanitize_identifier(raw_value: &str) -> String {
    let normalized = RE_NON_ALPHANUMERIC.replace_all(raw_value, "_");
    let normalized = RE_UNDERSCORES.replace_all(&normalized, "_");
    let normalized = normalized.trim_matches('_').to_string();

    if normalized.is_empty() {
        return "ts_bridge".to_string();
    }

    if RE_START_ALPHABETIC.is_match(&normalized) {
        normalized
    } else {
        format!("n_{}", normalized)
    }
}
use std::collections::HashSet;
use crate::ast_types::*;
use swc_common::sync::Lrc;
use swc_common::SourceMap;
use swc_common::Spanned;
use swc_common::SourceMapper;

pub struct CompileState<'a> {
    pub source_text: &'a str,
    pub cm: Lrc<SourceMap>,
    pub source_file_path: String,
    pub input_parameter_name: Option<String>,
    pub prefix: String,
    pub known_bindings: HashSet<String>,
    pub operations: Vec<BridgeOperation>,
    pub node_plans: Vec<BridgeNodePlan>,
    pub next_id: u32,
    pub temp_id: u32,
}

impl<'a> CompileState<'a> {
    pub fn new(source_text: &'a str, cm: Lrc<SourceMap>, source_file_path: String, input_parameter_name: Option<String>, prefix: String) -> Self {
        Self {
            source_text,
            cm,
            source_file_path,
            input_parameter_name,
            prefix,
            known_bindings: HashSet::new(),
            operations: Vec::new(),
            node_plans: Vec::new(),
            next_id: 0,
            temp_id: 0,
        }
    }

    pub fn create_node_id(&mut self, kind: &str, hint: &str) -> String {
        let index = self.next_id;
        self.next_id += 1;
        let sanitized_hint = sanitize_identifier(hint);
        format!("{}_{}_{:02}_{}", self.prefix, kind, index, sanitized_hint)
    }

    pub fn create_temp_binding(&mut self, hint: &str) -> String {
        let name = format!("__gg_temp_{}_{}", hint, self.temp_id);
        self.temp_id += 1;
        name
    }

    pub fn extract_source_location(&self, span: swc_common::Span) -> Option<SourceLocation> {
        if span.is_dummy() {
            return None;
        }
        let loc = self.cm.lookup_char_pos(span.lo);
        let end_loc = self.cm.lookup_char_pos(span.hi);
        Some(SourceLocation {
            line: loc.line as u32,
            column: loc.col_display as u32 + 1,
            end_line: Some(end_loc.line as u32),
            end_column: Some(end_loc.col_display as u32 + 1),
        })
    }

    pub fn extract_ghost_mass(&self, span: swc_common::Span) -> Option<serde_json::Value> {
        if span.is_dummy() {
            return None;
        }
        match self.cm.span_to_snippet(span) {
            Ok(snippet) => Some(serde_json::json!({ "source": snippet })),
            Err(_) => None,
        }
    }
}

pub fn resolve_expression(
    expr: &Expr,
    state: &CompileState,
    allow_runtime_identifiers: bool,
) -> Result<BridgeExpression, String> {
    match expr {
        Expr::Ident(ident) => {
            let text = ident.sym.to_string();
            if text == "undefined" {
                return Ok(BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Null });
            }
            if let Some(ref input_param) = state.input_parameter_name {
                if text == *input_param {
                    return Ok(BridgeExpression::Input { ghost_mass: None });
                }
            }
            if state.known_bindings.contains(&text) {
                return Ok(BridgeExpression::Binding { ghost_mass: None,  name: text });
            }
            if allow_runtime_identifiers {
                return Ok(BridgeExpression::Runtime { ghost_mass: None,  name: text });
            }
            Err(format!("Undeclared or unrecognized identifier '{}'", text))
        }
        Expr::Lit(lit) => {
            match lit {
                Lit::Str(s) => Ok(BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::String(s.value.to_string_lossy().into_owned()) }),
                Lit::Num(n) => Ok(BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Number(serde_json::Number::from_f64(n.value).unwrap()) }),
                Lit::Bool(b) => Ok(BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Bool(b.value) }),
                Lit::Null(_) => Ok(BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Null }),
                _ => Err("Unsupported literal type".to_string()),
            }
        }
        Expr::Tpl(tpl) => {
            if tpl.quasis.len() == 1 && tpl.exprs.is_empty() {
                Ok(BridgeExpression::Literal { ghost_mass: None, 
                    value: serde_json::Value::String(tpl.quasis[0].raw.to_string()),
                })
            } else {
                Err("Interpolated template literals are not supported in the TS bridge".to_string())
            }
        }
        Expr::Member(member) => {
            let target = resolve_expression(&member.obj, state, allow_runtime_identifiers)?;
            match &member.prop {
                MemberProp::Ident(ident) => {
                    Ok(BridgeExpression::Member { ghost_mass: None, 
                        target: Box::new(target),
                        property: ident.sym.to_string(),
                    })
                }
                MemberProp::Computed(computed) => {
                    match &*computed.expr {
                        Expr::Lit(Lit::Str(s)) => {
                            Ok(BridgeExpression::Index { ghost_mass: None, 
                                target: Box::new(target),
                                index: serde_json::Value::String(s.value.to_string_lossy().into_owned()),
                            })
                        }
                        Expr::Lit(Lit::Num(n)) => {
                            Ok(BridgeExpression::Index { ghost_mass: None, 
                                target: Box::new(target),
                                index: serde_json::Value::Number(serde_json::Number::from_f64(n.value).unwrap()),
                            })
                        }
                        _ => Err("Unsupported element access expression (only literal string/number keys are supported)".to_string()),
                    }
                }
                _ => Err("Unsupported property access expression".to_string())
            }
        }
        Expr::Array(array) => {
            let mut items = Vec::new();
            for item in &array.elems {
                if let Some(element) = item {
                    if element.spread.is_some() {
                        return Err("Unsupported array spread in bridge expression".to_string());
                    }
                    items.push(resolve_expression(&element.expr, state, allow_runtime_identifiers)?);
                }
            }
            Ok(BridgeExpression::Array { ghost_mass: None,  items })
        }
        Expr::Object(object) => {
            let mut entries = Vec::new();
            for prop in &object.props {
                match prop {
                    PropOrSpread::Prop(p) => {
                        match &**p {
                            Prop::Shorthand(ident) => {
                                let key = ident.sym.to_string();
                                let value = resolve_expression(&Expr::Ident(ident.clone()), state, allow_runtime_identifiers)?;
                                entries.push(BridgeObjectEntry { key, value });
                            }
                            Prop::KeyValue(kv) => {
                                let key = match &kv.key {
                                    PropName::Ident(ident) => ident.sym.to_string(),
                                    PropName::Str(s) => s.value.to_string_lossy().into_owned(),
                                    _ => return Err("Unsupported object literal property key".to_string())
                                };
                                let value = resolve_expression(&kv.value, state, allow_runtime_identifiers)?;
                                entries.push(BridgeObjectEntry { key, value });
                            }
                            _ => return Err("Unsupported object literal property".to_string())
                        }
                    }
                    _ => return Err("Unsupported object spread in bridge expression".to_string())
                }
            }
            Ok(BridgeExpression::Object { ghost_mass: None,  entries })
        }
        Expr::Unary(unary) => {
            if unary.op == UnaryOp::Minus {
                if let Expr::Lit(Lit::Num(n)) = &*unary.arg {
                    return Ok(BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Number(serde_json::Number::from_f64(-n.value).unwrap()) });
                }
            }
            Err("Unsupported prefix unary expression".to_string())
        }
        Expr::Await(await_expr) => {
            resolve_expression(&await_expr.arg, state, allow_runtime_identifiers)
        }
        _ => Err(format!("Unsupported TypeScript expression type: {:?}", expr)),
    }
}

pub fn resolve_call_plan(
    expr: &Expr,
    state: &mut CompileState,
    assign_to: Option<String>,
    node_hint: &str,
) -> Result<BridgeNodePlan, String> {
    let call_expr = match expr {
        Expr::Call(call) => call,
        Expr::Await(await_expr) => match &*await_expr.arg {
            Expr::Call(call) => call,
            _ => return Err("Expected a call expression".to_string()),
        },
        _ => return Err("Expected a call expression".to_string()),
    };

    let callee = resolve_expression(&call_expr.callee.clone().expect_expr(), state, true)?;
    
    let this_arg = match &*call_expr.callee.clone().expect_expr() {
        Expr::Member(member) => Some(resolve_expression(&member.obj, state, true)?),
        _ => None,
    };

    let mut args = Vec::new();
    for arg in &call_expr.args {
        if arg.spread.is_some() {
            return Err("Unsupported spread argument in bridge call".to_string());
        }
        args.push(resolve_expression(&arg.expr, state, false)?);
    }

    let node_id = state.create_node_id("call", node_hint);
    let plan = BridgeNodePlan::Call { ghost_mass: None, 
        node_id,
        handler_label: "TsBridgeCall".to_string(),
        callee,
        this_arg,
        args,
        assign_to,
        source_location: state.extract_source_location(expr.span()),
    };
    state.node_plans.push(plan.clone());
    Ok(plan)
}

pub fn compile_promise_all_operation(
    binding_names: Vec<String>,
    promise_all_call: &CallExpr,
    state: &mut CompileState,
) -> Result<(), String> {
    let branch_array = match promise_all_call.args.first() {
        Some(arg) => match &*arg.expr {
            Expr::Array(arr) => arr,
            _ => return Err("Promise.all bridge expects an array literal argument".to_string()),
        },
        None => return Err("Promise.all bridge expects an array literal argument".to_string()),
    };

    let mut branch_binding_names = Vec::new();
    if binding_names.len() > 1 || branch_array.elems.len() == binding_names.len() {
        if binding_names.len() != branch_array.elems.len() {
            return Err("Promise.all destructure length does not match the branch count".to_string());
        }
        for name in binding_names.clone() {
            branch_binding_names.push(name.clone());
            state.known_bindings.insert(name);
        }
    } else {
        let base_name = binding_names.first().cloned().unwrap_or_default();
        for i in 0..branch_array.elems.len() {
            branch_binding_names.push(state.create_temp_binding(&format!("{}_{}", base_name, i)));
        }
    }

    let mut branches = Vec::new();
    for (index, elem) in branch_array.elems.iter().enumerate() {
        if let Some(element) = elem {
            if element.spread.is_some() {
                return Err("Promise.all bridge does not support spread elements".to_string());
            }
            let assign_name = branch_binding_names.get(index).cloned();
            let hint = format!("branch_{}", index);
            branches.push(resolve_call_plan(&element.expr, state, assign_name, &hint)?);
        }
    }

    let join_node_id = state.create_node_id("join", "promise_all");
    let join_plan = BridgeNodePlan::Join { ghost_mass: None, 
        node_id: join_node_id,
        handler_label: "TsBridgeJoin".to_string(),
        source_location: state.extract_source_location(promise_all_call.span()),
    };
    state.node_plans.push(join_plan.clone());

    state.operations.push(BridgeOperation::Parallel {
        branches,
        join_plan,
    });

    if binding_names.len() == 1 {
        let binding_name = binding_names.first().unwrap().clone();
        let assign_node_id = state.create_node_id("assign", &binding_name);
        let assign_plan = BridgeNodePlan::Assign { ghost_mass: None, 
            node_id: assign_node_id,
            handler_label: "TsBridgeAssign".to_string(),
            binding_name: binding_name.clone(),
            expression: BridgeExpression::Array { ghost_mass: None, 
                items: branch_binding_names.into_iter().map(|name| BridgeExpression::Binding { ghost_mass: None,  name }).collect(),
            },
            source_location: state.extract_source_location(promise_all_call.span()),
        };
        state.known_bindings.insert(binding_name);
        state.node_plans.push(assign_plan.clone());
        state.operations.push(BridgeOperation::Assign { plan: assign_plan });
    }

    Ok(())
}

pub fn compile_variable_declaration(
    decl: &VarDeclarator,
    state: &mut CompileState,
) -> Result<(), String> {
    let init = match &decl.init {
        Some(expr) => expr,
        None => return Err("Bridge variable declarations require an initializer".to_string()),
    };

    let mut binding_names = Vec::new();
    match &decl.name {
        Pat::Ident(ident) => {
            binding_names.push(ident.id.sym.to_string());
        }
        Pat::Array(arr) => {
            for elem in &arr.elems {
                if let Some(Pat::Ident(ident)) = elem {
                    binding_names.push(ident.id.sym.to_string());
                } else {
                    return Err("Only simple identifier bindings are supported".to_string());
                }
            }
        }
        _ => return Err("Only simple identifier bindings are supported".to_string()),
    }

    let unwrapped_init = match &**init {
        Expr::Await(await_expr) => &await_expr.arg,
        expr => expr,
    };

    if let Expr::Call(call_expr) = unwrapped_init {
        if let Expr::Member(member) = &*call_expr.callee.clone().expect_expr() {
            if let Expr::Ident(ident) = &*member.obj {
                if ident.sym == "Promise" {
                    if let MemberProp::Ident(prop) = &member.prop {
                        if prop.sym == "all" {
                            return compile_promise_all_operation(binding_names, call_expr, state);
                        }
                    }
                }
            }
        }
    }

    if binding_names.len() != 1 {
        return Err("Only promise.all supports array destructuring".to_string());
    }
    let single_binding = binding_names.into_iter().next().unwrap();

    if let Expr::Call(_) = unwrapped_init {
        let plan = resolve_call_plan(init, state, Some(single_binding.clone()), &single_binding)?;
        state.known_bindings.insert(single_binding);
        state.operations.push(BridgeOperation::Call { plan });
        return Ok(());
    }

    let assign_node_id = state.create_node_id("assign", &single_binding);
    let assign_plan = BridgeNodePlan::Assign { ghost_mass: None, 
        node_id: assign_node_id,
        handler_label: "TsBridgeAssign".to_string(),
        binding_name: single_binding.clone(),
        expression: resolve_expression(init, state, false)?,
        source_location: state.extract_source_location(decl.span()),
    };
    
    state.known_bindings.insert(single_binding);
    state.node_plans.push(assign_plan.clone());
    state.operations.push(BridgeOperation::Assign { plan: assign_plan });
    
    Ok(())
}

pub fn compile_statement(stmt: &Stmt, state: &mut CompileState) -> Result<(), String> {
    match stmt {
        Stmt::Decl(Decl::Var(var_decl)) => {
            for decl in &var_decl.decls {
                compile_variable_declaration(decl, state)?;
            }
            Ok(())
        }
        Stmt::Expr(expr_stmt) => {
            let unwrapped_expr = match &*expr_stmt.expr {
                Expr::Await(await_expr) => &await_expr.arg,
                expr => expr,
            };
            if !unwrapped_expr.is_call() {
                return Err("Unsupported TypeScript statement (expected Call expression)".to_string());
            }
            let plan = resolve_call_plan(&expr_stmt.expr, state, None, "effect")?;
            state.operations.push(BridgeOperation::Call { plan });
            Ok(())
        }
        Stmt::Return(ret_stmt) => {
            if let Some(expr) = &ret_stmt.arg {
                let unwrapped = match &**expr {
                    Expr::Await(await_expr) => &await_expr.arg,
                    e => e,
                };
                if unwrapped.is_call() {
                    let return_binding = state.create_temp_binding("return");
                    let call_plan = resolve_call_plan(expr, state, Some(return_binding.clone()), "return")?;
                    state.operations.push(BridgeOperation::Call { plan: call_plan });

                    let ret_node_id = state.create_node_id("return", "result");
                    let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
                        node_id: ret_node_id,
                        handler_label: "TsBridgeReturn".to_string(),
                        expression: BridgeExpression::Binding { ghost_mass: None,  name: return_binding },
                        source_location: state.extract_source_location(ret_stmt.span()),
                    };
                    state.node_plans.push(ret_plan.clone());
                    state.operations.push(BridgeOperation::Return { plan: ret_plan });
                    return Ok(());
                }

                let ret_node_id = state.create_node_id("return", "result");
                let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
                    node_id: ret_node_id,
                    handler_label: "TsBridgeReturn".to_string(),
                    expression: resolve_expression(unwrapped, state, false)?,
                    source_location: state.extract_source_location(ret_stmt.span()),
                };
                state.node_plans.push(ret_plan.clone());
                state.operations.push(BridgeOperation::Return { plan: ret_plan });
                Ok(())
            } else {
                let ret_node_id = state.create_node_id("return", "void");
                let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
                    node_id: ret_node_id,
                    handler_label: "TsBridgeReturn".to_string(),
                    expression: BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Null },
                    source_location: state.extract_source_location(ret_stmt.span()),
                };
                state.node_plans.push(ret_plan.clone());
                state.operations.push(BridgeOperation::Return { plan: ret_plan });
                Ok(())
            }
        }
        _ => Err("Unsupported TypeScript statement".to_string()),
    }
}
